INSERT INTO book_clause_sources VALUES
('recording.assertion-not-truth', 'book_of_seed/05-evidence-and-knowledge/recording-and-knowledge-extraction.md', 'Recovered clauses for recorded-change witnesses / 05.Recording.A', 'Recording creates retrievable assertion-bearing material without establishing truth.'),
('recording.scoped-examination', 'book_of_seed/05-evidence-and-knowledge/recording-and-knowledge-extraction.md', 'Recovered clauses for recorded-change witnesses / 05.Recording.B', 'Examination-scoped recording remains bounded availability for examination.'),
('evidence.support-binding', 'book_of_seed/05-evidence-and-knowledge/evidence-provenance-and-explanation.md', 'Recovered clauses for support-binding witnesses / 05.Evidence.A', 'Evidence identity, existence, source context, subject, claim, authority, and provenance binding are distinct from fact standing.'),
('provenance.representation-applicability', 'book_of_seed/05-evidence-and-knowledge/evidence-provenance-and-explanation.md', 'Recovered clauses for support-binding witnesses / 05.Evidence.B', 'Provenance representation, applicability, verification, and producer occurrence remain distinct.'),
('testimony.not-fact', 'book_of_seed/05-evidence-and-knowledge/testimony-and-established-fact.md', 'Recovered clauses for support-binding witnesses / 05.Testimony.A', 'Testimony and evidence may be consumed as premise-relative input without becoming established fact.'),
('events.record-not-fact', 'book_of_seed/06-state-and-projection/events-facts-and-state.md', 'Initial resolution', 'Events record assertions; facts and state require separate standing.'),
('competency.bounded-relevance', 'book_of_seed/04-inquiry-and-examination/examination-methods-and-probes.md', 'Recovered clauses for bounded examination witnesses / 04.Examination.A', 'Applicability or relevance is distinct from selection, execution, and fact establishment.'),
('competency.lawful-inactivity', 'book_of_seed/04-inquiry-and-examination/examination-methods-and-probes.md', 'Recovered clauses for bounded examination witnesses / 04.Examination.B', 'Irrelevant, unsupported, insufficiently bound, or outside-authority material yields distinguishable lawful inactivity or unknown preservation.'),
('authority.no-expansion', 'book_of_seed/08-authority-communication-and-stopping/authority-scope.md', 'Initial resolution', 'Internal records cannot create or enlarge authority.'),
('refusal.non-performance', 'book_of_seed/08-authority-communication-and-stopping/refusal-and-non-performance.md', 'Initial resolution', 'Non-performance reasons must remain distinguishable from successful action.');
